import{_ as e,o as r,c as a,ag as n}from"./chunks/framework.DXGyWiRo.js";const i="/images/lekt3502.jpg",d="/images/lekt3501.jpg",l="/images/lekt3503.jpg",o="/images/lekt3504.jpg",b=JSON.parse('{"title":"Lektion 35","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/lektion35.md","filePath":"lektionen/lektion35.md"}'),s={name:"lektionen/lektion35.md"};function p(h,t,u,c,f,m){return r(),a("div",null,[...t[0]||(t[0]=[n('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="lektion-35" tabindex="-1">Lektion 35 <a class="header-anchor" href="#lektion-35" aria-label="Permalink to &quot;Lektion 35&quot;">​</a></h1><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><ul><li>35.1. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <ul><li>35.1.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe</li><li>35.1.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe</li></ul></li><li>35.2. Perfekt Typ IV: Wurzeln auf -ā / -ai</li><li>35.3. Perfekt Typ V: Wurzeln Konsonant-a-Konsonant <ul><li>35.3.1. Perfekt Typ Va: schwacher Stamm Tiefstufe</li><li>35.3.2. Perfekt Typ Vb: Wurzeln Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h. Schwacher Stamm ohne Reduplikation, mit -e-</li><li>35.3.3. Perfekt Typ Vc: Wurzeln Konsonant-a-Konsonant. Schwacher Stamm Hochstufe</li></ul></li><li>35.4. Wortliste</li><li>35.5. Übung</li></ul><h2 id="_35-1-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" tabindex="-1">35.1. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe <a class="header-anchor" href="#_35-1-perfekt-typ-iii-starker-stamm-hochstufe-dehnstufe" aria-label="Permalink to &quot;35.1. Perfekt Typ III: Starker Stamm Hochstufe/Dehnstufe&quot;">​</a></h2><p>Bildung:</p><p>starker Stamm:</p><ul><li>3.sg.P: Dehnstufe</li><li>2.sg.P: Hochstufe</li><li>1.sg.P: wahlweise Hochstufe oder Dehnstufe</li></ul><p>schwacher Stamm: siehe bei den Untertypen</p><h3 id="_35-1-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" tabindex="-1">35.1.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe <a class="header-anchor" href="#_35-1-1-perfekt-typ-iiia-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;35.1.1. Perfekt Typ IIIa: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Tiefstufe&quot;">​</a></h3><p>Bildung:</p><blockquote><p>schwacher Stamm: Tiefstufe</p></blockquote><p>Wird gebildet von Wurzeln der Typen:</p><ul><li>(Konsonant)-(Konsonant) - i/ī/u/ū</li><li>(Konsonant) - ṛ</li></ul><p>Vor vokalisch anlautender Endung wird ersetzt</p><ul><li>-i/-ī durch -iy</li><li>-u/-ū durch -uv,</li><li>-ṛ durch r</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>इ 2P</td><td>इयाय</td><td></td><td></td><td></td></tr><tr><td>iy-ai + a</td><td>ईयुर्</td><td></td><td></td><td></td></tr><tr><td>i + iy + ur</td><td></td><td></td><td></td><td></td></tr><tr><td>नी 1U</td><td>निनाय</td><td>निन्युर्</td><td></td><td></td></tr><tr><td>ni-nī + ur</td><td>निन्ये</td><td>निन्यिरे</td><td></td><td></td></tr><tr><td>स्तु 2U</td><td>तुष्टाव</td><td></td><td></td><td></td></tr><tr><td>tu + stau + a</td><td>तुष्टुवुर्</td><td></td><td></td><td></td></tr><tr><td>tu + stuv-ur</td><td>तुष्टुवे</td><td>तुष्टुविरे</td><td></td><td></td></tr><tr><td>पू</td><td>पुपाव</td><td></td><td></td><td></td></tr><tr><td>pu-pau + a</td><td>पुपुवुर्</td><td></td><td></td><td></td></tr><tr><td>pu-puv-ur</td><td>पुपुवे</td><td>पुपुविरे</td><td></td><td></td></tr><tr><td>कृ</td><td>चकार</td><td>चक्रुर्</td><td></td><td></td></tr><tr><td>ca-kr-ur</td><td>चक्रे</td><td>चक्रिरे</td><td></td><td></td></tr></tbody></table></blockquote><h3 id="_35-1-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" tabindex="-1">35.1.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe <a class="header-anchor" href="#_35-1-2-perfekt-typ-iiib-starker-stamm-hochstufe-dehnstufe-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;35.1.2. Perfekt Typ IIIb: Starker Stamm Hochstufe/Dehnstufe, schwacher Stamm Hochstufe&quot;">​</a></h3><p>Bildung:</p><blockquote><p>schwacher Stamm: Hochstufe</p></blockquote><p>Wird gebildet von Wurzeln der Typen:</p><ul><li>(Konsonant)-(Konsonant)-ṝ</li><li>Konsonant-Konsonant-ṛ (d.h. Wurzeln auf -ṛ, wenn diesem mehrere Konsonanten vorausgehen)</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>पॄ 3P</td><td>पपार</td><td>पपरुर्</td><td></td><td></td></tr><tr><td>स्मृ 1P</td><td>समार</td><td>सस्मरुर्</td><td></td><td></td></tr><tr><td>संस्कृ 8U</td><td>सञ्चस्कार</td><td></td><td></td><td></td></tr><tr><td>sam + ca-skār-a</td><td>सञ्चस्करुर्</td><td>सञ्चस्करे</td><td>सञ्चस्करिरे</td><td></td></tr></tbody></table></blockquote><h2 id="_35-2-perfekt-typ-iv-wurzeln-auf-a-ai" tabindex="-1">35.2. Perfekt Typ IV: Wurzeln auf -ā / -ai <a class="header-anchor" href="#_35-2-perfekt-typ-iv-wurzeln-auf-a-ai" aria-label="Permalink to &quot;35.2. Perfekt Typ IV: Wurzeln auf -ā / -ai&quot;">​</a></h2><p>Bildung:</p><blockquote><p>starker Stamm:</p><ul><li>3./1. sg. P Perfekt endet auf -au</li><li>2. sg. P : Hochstufe -ā oder Tiefstufe -i</li></ul><p>schwacher Stamm</p><ul><li>vor Konsonant: Tiefstufe -i</li><li>vor Vokal: Tiefstufe Ø</li></ul></blockquote><p>Wird gebildet von Wurzeln auf -ā / -āi</p><p>Beispiel:</p><blockquote><p>| Wurzel | 3.sg.Perf.P<br> 1.sg.Perf.P | 3.pl.Perf.P | 3.sg.Perf.Ā | 3.pl.Perf.Ā | | --- | --- | --- | --- | --- | | दा 3U | ददौ 1 | ददुर्<br> da-d-ur | ददे | ददिरे<br> da-d-i-re |</p></blockquote><p>1 die Form ददौ ist noch nicht befriedigend erklärt (siehe Thumb-Hauschild 1,2 S. 290ff.)</p><h2 id="_35-3-perfekt-typ-v-wurzeln-konsonant-a-konsonant" tabindex="-1">35.3. Perfekt Typ V: Wurzeln Konsonant-a-Konsonant <a class="header-anchor" href="#_35-3-perfekt-typ-v-wurzeln-konsonant-a-konsonant" aria-label="Permalink to &quot;35.3. Perfekt Typ V: Wurzeln Konsonant-a-Konsonant&quot;">​</a></h2><p>Bildung:</p><blockquote><p>starker Stamm:</p><ul><li>3.sg.P: Dehnstufe</li><li>2.sg.P: Hochstufe</li><li>1.sg.P: wahlweise Hochstufe oder Dehnstufe</li></ul><p>schwacher Stamm: siehe Untertypen</p></blockquote><p>Wird gebildet von Wurzeln des Typs (Konsonant)-Konsonant-a-Konsonant</p><h3 id="_35-3-1-perfekt-typ-va-schwacher-stamm-tiefstufe" tabindex="-1">35.3.1. Perfekt Typ Va: schwacher Stamm Tiefstufe <a class="header-anchor" href="#_35-3-1-perfekt-typ-va-schwacher-stamm-tiefstufe" aria-label="Permalink to &quot;35.3.1. Perfekt Typ Va: schwacher Stamm Tiefstufe&quot;">​</a></h3><p>Bildung</p><blockquote><p>schwacher Stamm: Tiefstufe</p></blockquote><p>Wird gebildet u.a. von den Wurzeln:</p><ul><li>गम्</li><li>हन्</li><li>जन्</li><li>वच्</li><li>वद्</li><li>यज्</li></ul><p>Beispiele:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>गम् 1P</td><td>जगाम</td><td>जग्मुर्</td><td></td><td></td></tr><tr><td>ja-gm-ur</td><td></td><td></td><td></td><td></td></tr><tr><td>हन् 2P</td><td>जघान</td><td></td><td></td><td></td></tr><tr><td>ja-ghān-a</td><td>जघ्नुर्</td><td></td><td></td><td></td></tr><tr><td>जन् 4Ā</td><td></td><td></td><td>जज्ञे</td><td></td></tr><tr><td>ja-jñ-e</td><td>जज्ञिरे</td><td></td><td></td><td></td></tr><tr><td>वच् 2P</td><td>उवाच</td><td>ऊचुर्</td><td></td><td></td></tr><tr><td>u +ucur</td><td></td><td></td><td></td><td></td></tr><tr><td>वद् 1P</td><td>उवाद</td><td>ऊदुर्</td><td>&lt;उदे&gt;</td><td>&lt;उदिरे&gt;</td></tr><tr><td>यज् 1U</td><td>इयाज</td><td>ईजुर्</td><td></td><td></td></tr><tr><td>i + ij-ur</td><td>ईजे</td><td>ईजिरे</td><td></td><td></td></tr></tbody></table></blockquote><h3 id="_35-3-2-perfekt-typ-vb-wurzeln-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" tabindex="-1">35.3.2. Perfekt Typ Vb: Wurzeln Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h. Schwacher Stamm ohne Reduplikation, mit -e- <a class="header-anchor" href="#_35-3-2-perfekt-typ-vb-wurzeln-konsonant-a-konsonant-anfangskonsonant-kein-guttural-aspirat-h-schwacher-stamm-ohne-reduplikation-mit-e" aria-label="Permalink to &quot;35.3.2. Perfekt Typ Vb: Wurzeln Konsonant-a-Konsonant, Anfangskonsonant kein Guttural, Aspirat, h. Schwacher Stamm ohne Reduplikation, mit -e-&quot;">​</a></h3><p>Bildung:</p><blockquote><p>schwacher Stamm: keine Reduplikation. Ersetzung des -a- der Wurzel durch -e-<br> (zur Erklärung siehe Thumb-Hauschild 1,2 S. 286f.)</p></blockquote><p>Wird gebildet von Wurzeln mit -a- zwischen zwei einfachen Konsonanten, deren Anfangskonsonant in der Reduplikationssilbe nicht verändert wird (d.h. deren Anfangskonsonant kein Guttural, Aspirat oder h ist)</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>पव् 1U</td><td>पपाच</td><td>पेचुर्</td><td>पेचे</td><td>पेचिरे</td></tr></tbody></table></blockquote><h3 id="_35-3-3-perfekt-typ-vc-wurzeln-konsonant-a-konsonant-schwacher-stamm-hochstufe" tabindex="-1">35.3.3. Perfekt Typ Vc: Wurzeln Konsonant-a-Konsonant. Schwacher Stamm Hochstufe <a class="header-anchor" href="#_35-3-3-perfekt-typ-vc-wurzeln-konsonant-a-konsonant-schwacher-stamm-hochstufe" aria-label="Permalink to &quot;35.3.3. Perfekt Typ Vc: Wurzeln Konsonant-a-Konsonant. Schwacher Stamm Hochstufe&quot;">​</a></h3><p>Bildung:</p><blockquote><p>schwacher Stamm: Hochstufe</p></blockquote><p>Wird gebildet von allen anderen Wurzeln mit mittlerem -a-, d.h. Wurzeln mit mittlerem -a-</p><ul><li>die mit zwei Konsonanten beginnen</li><li>die mit Guttural beginnen</li><li>die mit Aspirat beginnen</li><li>die mit h beginnen</li></ul><p>sofern sie nicht zu Perfekt Typ Va gehören.</p><p>Beispiel:</p><blockquote><table tabindex="0"><thead><tr><th>Wurzel</th><th>3.sg.Perf.P</th><th>3.pl.Perf.P</th><th>3.sg.Perf.Ā</th><th>3.pl.Perf.Ā</th></tr></thead><tbody><tr><td>क्रम्  1U</td><td>चक्राम</td><td>चक्रमुर्</td><td>चक्रमे</td><td>चक्रमिरे</td></tr></tbody></table></blockquote><h2 id="_35-4-wortliste" tabindex="-1">35.4. Wortliste <a class="header-anchor" href="#_35-4-wortliste" aria-label="Permalink to &quot;35.4. Wortliste&quot;">​</a></h2><p>नश् 4P नश्यति : verloren gehen, zugrundegehen, verschwinden</p><blockquote><p>Perf. Vb ननाश, नेशुर्<br> Fut. नशिष्यति । नङ्क्ष्यति<br> Kaus. नाशयति<br> PPP नष्ट</p></blockquote><p>नश् + प्र 4P प्रणश्यति : verschwinden, verloren gehen, zugrundegehen</p><p>क्रम् 1U क्रामति, 4P क्राम्यति : schreiten, gehen</p><blockquote><p>Perf. Vc चक्राम, चक्रमुर्<br> Fut. क्रमिष्यति<br> Pass. क्रम्यते<br> Kaus. क्रमयति<br> PPP क्रान्त<br> Inf. क्रमितुम्<br> Kaus. क्रमित्वा । क्रन्त्वा । क्रान्त्वा</p></blockquote><p><img src="'+i+'" alt=""><br> Abb.: क्रामन्ति<br> [Bildquelle: Curt Carnemark / World Bank. -- <a href="http://www.flickr.com/photos/worldbank/2182732473/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/worldbank/2182732473/</a>. -- Zugriff am 2008-12-28. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>गै 1P यायति (gai + a-ti): singen, in singendem Ton rezitieren, in gebundener Rede verkünden</p><blockquote><p>Perf. IV जगौ, जगुर्<br> Fut. गास्यति<br> Pass. गीयते<br> Kaus. गापयति<br> PPP गीत<br> Inf. गातुम्</p><p>davon:</p><p>गीता f.: Lied Gesang</p><p><img src="'+d+'" alt=""><br> Abb.: जगुः<br> Kaadu Malleswara Temple, Bangalore = ಬೆಂಗಳೂರು<br> [Bildquelle: Samuelraj @. -- <a href="http://www.flickr.com/photos/samuelraj/2946969732/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/samuelraj/2946969732/</a>. -- Zugriff am 2008-12-28. -- <a href="http://creativecommons.org/licenses/by-nc/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, keine kommerzielle Nutzung)]</p></blockquote><h2 id="_35-5-ubung" tabindex="-1">35.5. Übung <a class="header-anchor" href="#_35-5-ubung" aria-label="Permalink to &quot;35.5. Übung&quot;">​</a></h2><p>A) Bilden Sie zu den folgenden Verbformen die entsprechenden Perfektformen:</p><ol><li><p>गायन्ति</p></li><li><p>स्मरन्ति</p></li><li><p>एष्यति</p></li><li><p>गच्छन्ति</p></li><li><p>कुरुते</p></li><li><p>नेष्यन्ते</p></li><li><p>जायते</p></li><li><p>जानाति</p></li><li><p>संस्करोति</p></li><li><p>पुनीते</p></li><li><p>बिभ्यति</p></li><li><p>पिपुरति</p></li><li><p>दत्ते</p></li><li><p>यजन्ते</p></li><li><p>भजन्ति unregelmäßig, nach Typ Vb!</p></li><li><p>वक्ति</p></li><li><p>अदधुः</p></li><li><p>बिभ्रते</p></li><li><p>मरिष्यन्ति</p></li><li><p>अशक्नुवन्</p></li><li><p>अवदन्</p></li><li><p>अपिबत्</p></li><li><p>अपान्</p></li><li><p>अलभत</p></li><li><p>अहन्</p></li><li><p>मन्यन्ते</p></li><li><p>अक्रामन्</p></li><li><p>अशृण्वन्</p></li><li><p>मिमते<br><img src="'+l+'" alt=""><br> Abb.: मिमते<br> Vadaseri<br> [Bildquelle: kifo. -- <a href="http://www.flickr.com/photos/turningpoint/2365474/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/turningpoint/2365474/</a>. -- Zugriff am 2008-12-28. -- <a href="http://creativecommons.org/licenses/by-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Commons Lizenz (Namensnennung, share alike)]</p></li><li><p>अपद्यत</p></li><li><p>सुनोति</p></li><li><p>अतिष्ठत्</p></li><li><p>पतिष्यन्ति</p></li><li><p>अपचत्</p></li><li><p>अजहुर्</p></li><li><p>धक्ष्यन्ति</p></li><li><p>स्तौति</p></li><li><p>तनुते</p></li><li><p>अचरत्</p></li><li><p>जुह्वति</p></li><li><p>अहरत्</p></li></ol><p>B) Übersetzen Sie:</p><p>एकस्मिन्नेव काले क्षत्रियो महान्यष्टु्मुपचक्रमे । तस्य यज्ञपशुमिन्द्रो जहार । प्रनष्टे तु पशौ दुर्ब्राह्मणः क्षत्रियमब्रवीत् । पशुर्हृतः क्षत्रियस्य दुर्नयादिति ॥१॥</p><p>रामो ऽपुत्र आस । स पुत्रमियेष न तु लेभे । तस्माद्देवानीजे ब्रह्मचर्यादिव्रतानि च चकार । देवा रामस्येष्टिं शुश्रुवू रामाय चेष्टपुत्रं ददुः ॥२॥</p><p>ब्राह्मण्यो यज्ञाय घृतं पेचुः । ब्राह्मणीषु पचन्तीषु ब्राह्मणा यज्ञस्थानं सञ्चस्करुः । ततः क्षत्रियाः शिवादिदेवानीजिरे ब्राह्मणाश्चेजुः ॥३॥</p><p><img src="'+o+'" alt=""><br> Abb.: ... ब्राह्मणाश्चेजुः<br> यज्ञ, Shiva ashram, Kothavala, Ganeshpuri, 80 km von Mumbai (मुंबई) entfernt<br> [Bildquelle: Dey. -- <a href="http://www.flickr.com/photos/dey/462784131/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/dey/462784131/</a>.  -- Zugriff am 2008-12-28. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer"></a>Creative Comons Lizenz (Namensnennung, keine kommerzielle Nutzung, Share alike)]</p><p>अर्हन्तः कुलबन्धनं बिभिदुर्लोभं च क्रोधं च मोहं च रुरुधुः सत्यं प्रजज्ञुर्दुःखान्मुक्ता मोक्षसुखमापुः ॥४॥</p><p>C) Wandeln Sie die Sätze der Übung B) um, indem Sie Perfekta durch Imperfekta ersetzen.</p>',76)])])}const g=e(s,[["render",p]]);export{b as __pageData,g as default};
